return () => {
  const totalPoints = 300;
  const end = 6 * Math.PI;
  const step = end / (totalPoints - 1);
  const points1 = [];
  const points2 = [];
  for (let i = 0; i < totalPoints; i++) {
    const t = i * step;
    points1.push({
      x: t,
      y: Math.sin(t)
    });
    points2.push({
      x: t,
      y: Math.cos(t)
    });
  }
  return { output: [points1, points2] };
};

return () => {
  const points = [];
  const N = 520;
  // First pass: compute raw coordinates
  const raw = [];
  for (let i = 0; i < N; i++) {
    const t = (i / N) * 2 * Math.PI;
    const x = 16 * Math.pow(Math.sin(t), 3);
    const y = 13 * Math.cos(t) - 5 * Math.cos(2*t) - 2 * Math.cos(3*t) - Math.cos(4*t);
    raw.push({ x, y });
  }
  // Find bounds
  let minX = Infinity, maxX = -Infinity, minY = Infinity, maxY = -Infinity;
  for (const p of raw) {
    if (p.x < minX) minX = p.x;
    if (p.x > maxX) maxX = p.x;
    if (p.y < minY) minY = p.y;
    if (p.y > maxY) maxY = p.y;
  }
  // Translate to first quadrant (scale to reasonable size, e.g., 0-100)
  const rangeX = maxX - minX || 1;
  const rangeY = maxY - minY || 1;
  const scale = 100;
  for (const p of raw) {
    points.push({
      x: ((p.x - minX) / rangeX) * scale,
      y: ((p.y - minY) / rangeY) * scale
    });
  }
  return { output: points };
};

return () => {
  const startTime = dayjs('2026-07-19 14:10:12').valueOf();
  const points = 150;
  const interval = 200;

  // Array 1: Production output
  const data1 = [];
  let baseValue1 = 75;
  for (let i = 0; i < points; i++) {
    const x = startTime + i * interval;
    const trend = i * 0.05;
    const periodic = 8 * Math.sin(i * 2 * Math.PI / 30);
    const noise = (Math.random() - 0.5) * 3;
    let y = baseValue1 + trend + periodic + noise;
    if (Math.random() < 0.05) {
      y += (Math.random() - 0.5) * 15;
    }
    y = Math.round(y * 100) / 100;
    data1.push({ x, y });
  }

  // Array 2: Temperature/secondary metric
  const data2 = [];
  let baseValue2 = 68;
  for (let i = 0; i < points; i++) {
    const x = startTime + i * interval;
    const trend = -i * 0.03; // slight downward trend
    const periodic = 6 * Math.cos(i * 2 * Math.PI / 45); // different period
    const noise = (Math.random() - 0.5) * 2;
    let y = baseValue2 + trend + periodic + noise;
    if (Math.random() < 0.04) {
      y += (Math.random() - 0.5) * 12;
    }
    y = Math.round(y * 100) / 100;
    data2.push({ x, y });
  }

  return { output: [data1, data2] };
};
